class Solution:
    def checkInclusion(self, s1: str, s2: str) -> bool:
        def is_permutation(window, s1):
            return sorted(window) == sorted(s1)

        s1_len = len(s1)
        s2_len = len(s2)

        for i in range(s2_len - s1_len + 1):
            window = s2[i:i + s1_len]
            if is_permutation(window, s1):
                return True

        return False
